//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    String types;
    Scripts scripts;
    List<String> keywords;
    Repository repository;
    String author;
    String license;
    DevDependencies devDependencies;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.types,
        required this.scripts,
        required this.keywords,
        required this.repository,
        required this.author,
        required this.license,
        required this.devDependencies,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        types: json["types"],
        scripts: Scripts.fromJson(json["scripts"]),
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        repository: Repository.fromJson(json["repository"]),
        author: json["author"],
        license: json["license"],
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "types": types,
        "scripts": scripts.toJson(),
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "repository": repository.toJson(),
        "author": author,
        "license": license,
        "devDependencies": devDependencies.toJson(),
    };
}

class DevDependencies {
    String typescriptEslintEslintPlugin;
    String typescriptEslintParser;
    String eslint;
    String eslintPluginImport;
    String typedoc;
    String typescript;

    DevDependencies({
        required this.typescriptEslintEslintPlugin,
        required this.typescriptEslintParser,
        required this.eslint,
        required this.eslintPluginImport,
        required this.typedoc,
        required this.typescript,
    });

    factory DevDependencies.fromJson(Map<String, dynamic> json) => DevDependencies(
        typescriptEslintEslintPlugin: json["@typescript-eslint/eslint-plugin"],
        typescriptEslintParser: json["@typescript-eslint/parser"],
        eslint: json["eslint"],
        eslintPluginImport: json["eslint-plugin-import"],
        typedoc: json["typedoc"],
        typescript: json["typescript"],
    );

    Map<String, dynamic> toJson() => {
        "@typescript-eslint/eslint-plugin": typescriptEslintEslintPlugin,
        "@typescript-eslint/parser": typescriptEslintParser,
        "eslint": eslint,
        "eslint-plugin-import": eslintPluginImport,
        "typedoc": typedoc,
        "typescript": typescript,
    };
}

class Repository {
    String type;
    String url;

    Repository({
        required this.type,
        required this.url,
    });

    factory Repository.fromJson(Map<String, dynamic> json) => Repository(
        type: json["type"],
        url: json["url"],
    );

    Map<String, dynamic> toJson() => {
        "type": type,
        "url": url,
    };
}

class Scripts {
    String build;
    String lint;
    String typedoc;

    Scripts({
        required this.build,
        required this.lint,
        required this.typedoc,
    });

    factory Scripts.fromJson(Map<String, dynamic> json) => Scripts(
        build: json["build"],
        lint: json["lint"],
        typedoc: json["typedoc"],
    );

    Map<String, dynamic> toJson() => {
        "build": build,
        "lint": lint,
        "typedoc": typedoc,
    };
}
